oxy_webhelp_navlinks = {"agent_cloud_RSC-d30753e50676":{"topics":[{"title":"Introduction to Agent Cloud","href":"agent_cloud\/agent_cloud_overview.html","menu":{"hasChildren":false},"tocID":"tocId-d30753e50696","next":"tocId-d30753e50696"},{"title":"High-level implementation workflow","shortdesc":"<p class=\"shortdesc\">Follow this end-to-end workflow to set up <span class=\"ph\">Agent Cloud<\/span>, connect your AI         platforms, configure governance, and begin monitoring AI agent activity in your         environment.<\/p>","href":"agent_cloud\/high_level_implementation_workflow.html","attributes":{"data-id":"high_level_implementation_workflow"},"menu":{"hasChildren":false},"tocID":"high_level_implementation_workflow-d30753e50764","topics":[]},{"title":"Quick links","shortdesc":"<p class=\"shortdesc\">Quick access to the most common setup, governance, monitoring, and rewind tasks in             <span class=\"ph\">Agent Cloud<\/span>.<\/p>","href":"agent_cloud\/quick_links.html","attributes":{"data-id":"quick_links"},"menu":{"hasChildren":false},"tocID":"quick_links-d30753e50778","topics":[]},{"title":"Plan your <span class=\"ph\">Agent Cloud<\/span> deployment","shortdesc":"<p class=\"shortdesc\">Before connecting AI platforms or configuring policies, complete three planning steps:         confirm your environment meets the requirements, review best practices for your AI agents,         and decide where <span class=\"ph\">Agent Cloud<\/span>'s data plane will run.<\/p>","href":"agent_cloud\/plan_agent_cloud_deployment.html","attributes":{"data-id":"plan_agent_cloud_deployment"},"menu":{"hasChildren":false},"tocID":"plan_agent_cloud_deployment-d30753e50792","next":"plan_agent_cloud_deployment-d30753e50792"},{"title":"Connect your AI platforms","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Agent Cloud<\/span> connects to the AI platforms, frameworks, and agent         infrastructure in your environment. The connection method depends on whether your AI agents         use a native platform, endpoint detection, or a custom model gateway.<\/p>","href":"agent_cloud\/configure_ai_connections.html","attributes":{"data-id":"configure_ai_connections"},"menu":{"hasChildren":false},"tocID":"configure_ai_connections-d30753e51138","next":"configure_ai_connections-d30753e51138"},{"title":"Onboard <span class=\"ph\">Agent Cloud<\/span>","shortdesc":"<p class=\"shortdesc\">After setting up your data plane and configuring your AI platform connections,         complete onboarding in <span class=\"ph\">RSC<\/span> to activate <span class=\"ph\">Agent Cloud<\/span> in your         environment. Onboarding creates the model router that connects your agents to the LLM         providers <span class=\"ph\">Agent Cloud<\/span> monitors.<\/p>","href":"agent_cloud\/onboard_ai_operations.html","attributes":{"data-id":"onboard_ai_operations"},"menu":{"hasChildren":false},"tocID":"onboard_ai_operations-d30753e51862","next":"onboard_ai_operations-d30753e51862"},{"title":"Manage <span class=\"ph\">Agent Cloud<\/span> policies","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Agent Cloud<\/span> policies define the governance rules for AI agent behavior.         Enable system policies for broad protection, then create custom policies for requirements         specific to your organization.<\/p>","href":"agent_cloud\/manage_agent_operations_policies.html","attributes":{"data-id":"manage_agent_operations_policies"},"menu":{"hasChildren":false},"tocID":"manage_agent_operations_policies-d30753e51901","next":"manage_agent_operations_policies-d30753e51901"},{"title":"Monitor AI agent activity","shortdesc":"<p class=\"shortdesc\">Use the <span class=\"ph\">Agent Cloud<\/span> UI to maintain continuous visibility into what your         AI agents are doing, which tools they are using, and whether they are violating your         policies.<\/p>","href":"agent_cloud\/monitor_analyze_ai_agent_activity.html","attributes":{"data-id":"monitor_analyze_ai_agent_activity"},"menu":{"hasChildren":false},"tocID":"monitor_analyze_ai_agent_activity-d30753e52015","next":"monitor_analyze_ai_agent_activity-d30753e52015"},{"title":"Rewind AI agent violations","shortdesc":"<p class=\"shortdesc\">When an AI agent action causes an unintended or unauthorized data change, use <span class=\"ph\">Agent Cloud<\/span>'s Rewind feature to reverse the specific change without restoring         the entire system.<\/p>","href":"agent_cloud\/rewind_agent_violations.html","attributes":{"data-id":"rewind_agent_violations"},"menu":{"hasChildren":false},"tocID":"rewind_agent_violations-d30753e52276","next":"rewind_agent_violations-d30753e52276"}]}};